function esc(value) {
  return String(value).replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

function route(slug, lang) { return `/${lang === 'tr' ? 'tr/' : ''}${slug}/`; }
function label(page, lang) { return page[lang].h1; }
function rootLink(lang) { return '/'; }

function sectionHtml(section) {
  const [title, paragraphs, callout] = section;
  return `<section class="article-section"><h2>${esc(title)}</h2>${paragraphs.map((p) => `<p>${esc(p)}</p>`).join('')}${callout ? `<div class="callout"><strong>${esc(callout[0])}</strong><br>${esc(callout[1])}</div>` : ''}</section>`;
}

function schemaFor(page, lang, canonical) {
  const copy = page[lang];
  const crumbs = [
    { '@type':'ListItem', position:1, name:ui[lang].home, item:site+'/' },
    { '@type':'ListItem', position:2, name:copy.h1, item:canonical },
  ];
  const graph = [
    {'@type':'Organization','@id':site+'/#organization',name:'GOKTIGIN BILISIM TEKNOLOJI LIMITED SIRKETI',url:site+'/',logo:site+'/assets/images/large-logo.png',email:'hello@goktigin.com'},
    {'@type':'WebSite','@id':site+'/#website',url:site+'/',name:'Chaput',publisher:{'@id':site+'/#organization'},inLanguage:['en','tr']},
    {'@type':'WebPage','@id':canonical+'#webpage',url:canonical,name:copy.title,description:copy.description,inLanguage:lang,isPartOf:{'@id':site+'/#website'},about:{'@id':site+'/#app'}},
    {'@type':'MobileApplication','@id':site+'/#app',name:'Chaput',applicationCategory:'SocialNetworkingApplication',operatingSystem:'Android, iOS',url:site+'/',downloadUrl:[iosUrl,androidUrl],publisher:{'@id':site+'/#organization'}},
    {'@type':'BreadcrumbList','@id':canonical+'#breadcrumbs',itemListElement:crumbs},
    {'@type':'FAQPage','@id':canonical+'#faq',mainEntity:copy.faq.map(([q,a])=>({'@type':'Question',name:q,acceptedAnswer:{'@type':'Answer',text:a}}))},
  ];
  if (page.kind === 'guide') graph.push({'@type':'Article','@id':canonical+'#article',headline:copy.h1,description:copy.description,datePublished:'2026-07-14',dateModified:updated,author:{'@id':site+'/#organization'},publisher:{'@id':site+'/#organization'},mainEntityOfPage:{'@id':canonical+'#webpage'},inLanguage:lang});
  return JSON.stringify({'@context':'https://schema.org','@graph':graph}).replace(/</g,'\\u003c');
}

function render(page, lang) {
  const copy = page[lang];
  const t = ui[lang];
  const canonicalPath = route(page.slug, lang);
  const alternateLang = lang === 'en' ? 'tr' : 'en';
  const canonical = site + canonicalPath;
  const image = `${site}/assets/images/screenshots/${lang}_${page.image}.png`;
  const related = (relatedMap[page.slug] || []).map((slug) => bySlug.get(slug)).filter(Boolean);
  const relatedCards = related.map((item) => `<a class="related-link" href="${route(item.slug,lang)}"><strong>${esc(label(item,lang))}</strong><span>${esc(item[lang].description)}</span></a>`).join('');
  const toc = copy.sections.map((s,i)=>`<li><a href="#section-${i+1}">${esc(s[0])}</a></li>`).join('');
  const sections = copy.sections.map((s,i)=>sectionHtml(s).replace('<section class="article-section">',`<section class="article-section" id="section-${i+1}">`)).join('');
  const faq = copy.faq.map(([q,a])=>`<details class="faq-item"><summary>${esc(q)}</summary><p>${esc(a)}</p></details>`).join('');
  const langHref = route(page.slug, alternateLang);
  return `<!doctype html>
<html lang="${lang}">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=5">
<title>${esc(copy.title)}</title>
<meta name="description" content="${esc(copy.description)}">
<meta name="author" content="GOKTIGIN BILISIM TEKNOLOJI LIMITED SIRKETI">
<meta name="robots" content="index,follow,max-image-preview:large,max-snippet:-1,max-video-preview:-1">
<link rel="canonical" href="${canonical}">
<link rel="alternate" hreflang="${lang}" href="${canonical}">
<link rel="alternate" hreflang="${alternateLang}" href="${site+langHref}">
<link rel="alternate" hreflang="x-default" href="${site+route(page.slug,'en')}">
<meta property="og:type" content="${page.kind === 'guide' ? 'article' : 'website'}">
<meta property="og:site_name" content="Chaput">
<meta property="og:title" content="${esc(copy.title)}">
<meta property="og:description" content="${esc(copy.description)}">
<meta property="og:url" content="${canonical}">
<meta property="og:image" content="${image}">
<meta property="og:image:alt" content="${esc(copy.h1)}">
<meta property="og:locale" content="${lang === 'tr' ? 'tr_TR' : 'en_US'}">
<meta name="twitter:card" content="summary_large_image">
<meta name="twitter:title" content="${esc(copy.title)}">
<meta name="twitter:description" content="${esc(copy.description)}">
<meta name="twitter:image" content="${image}">
<meta name="theme-color" content="#f6f8fa">
<link rel="icon" href="/favicon.ico">
<link rel="apple-touch-icon" href="/apple-touch-icon.png">
<link rel="stylesheet" href="/assets/content.css">
<script type="application/ld+json">${schemaFor(page,lang,canonical)}</script>
</head>
<body data-page-kind="${esc(page.kind)}" data-page-language="${lang}">
<a class="skip-link" href="#main">${esc(t.skip)}</a>
<header class="site-header"><div class="content-shell site-header__inner">
  <a class="brand" href="${rootLink(lang)}" aria-label="Chaput"><img src="/assets/images/appicon.png" width="52" height="52" alt=""><span>Chaput</span></a>
  <nav class="site-nav" aria-label="${lang === 'tr' ? 'Ana menü' : 'Main menu'}">
    <a href="${route('what-is-chaput',lang)}">${esc(t.navProduct)}</a><a href="${route('guides',lang)}">${esc(t.navGuides)}</a><a href="${route('use-cases',lang)}">${esc(t.navCreators)}</a><a href="${route('goth',lang)}">${esc(t.navCommunity)}</a>
    <a class="language-switch" href="${langHref}" hreflang="${alternateLang}">${esc(t.language)}</a>
    <button class="theme-toggle" type="button" data-theme-toggle data-dark-label="${esc(t.dark)}" data-light-label="${esc(t.light)}" aria-label="${esc(t.dark)}">◐</button>
  </nav>
</div></header>
<main id="main" class="content-shell">
  <nav class="breadcrumb" aria-label="Breadcrumb"><a href="/">${esc(t.home)}</a><span aria-hidden="true">/</span><span aria-current="page">${esc(copy.h1)}</span></nav>
  <section class="content-hero">
    <div class="content-hero__copy"><p class="eyebrow">${esc(copy.eyebrow)}</p><h1>${esc(copy.h1)}</h1><p class="answer-first">${esc(copy.answer)}</p><div class="hero-actions"><a class="button" href="#download">${esc(t.download)}</a><a class="button button--secondary" href="${route('how-chaput-works',lang)}">${esc(t.learn)}</a></div>${page.kind === 'guide' ? `<div class="byline"><span>${esc(t.published)}</span><span>${esc(t.updated)} ${updated}</span></div>` : ''}</div>
    <div class="content-hero__visual"><img src="/assets/images/screenshots/${lang}_${page.image}.png" width="1243" height="2689" alt="${esc(copy.h1)}" loading="eager" fetchpriority="high"></div>
  </section>
  <div class="content-layout"><article>${sections}<section class="article-section" id="faq"><h2>${lang === 'tr' ? 'Sık sorulan sorular' : 'Frequently asked questions'}</h2><div class="faq-list">${faq}</div></section></article>
    <aside class="content-aside"><section class="aside-card"><h2>${esc(t.contents)}</h2><ul>${toc}<li><a href="#faq">${lang === 'tr' ? 'Sık sorulan sorular' : 'Frequently asked questions'}</a></li></ul></section><section class="aside-card"><h2>${lang === 'tr' ? 'Temel bilgiler' : 'Key facts'}</h2><p>${esc(t.age)}</p></section></aside>
  </div>
  <section aria-labelledby="related-title"><h2 id="related-title">${esc(t.related)}</h2><div class="related-links">${relatedCards}</div></section>
  <section class="download-band" id="download"><h2>${esc(t.storeTitle)}</h2><p>${esc(t.storeText)}</p><div class="store-buttons"><a class="store-button" data-store-target="android" href="${androidUrl}" target="_blank" rel="noopener noreferrer"><img src="/assets/images/google-play-badge.png" width="646" height="250" alt="${esc(t.playStore)}"></a><a class="store-button" data-store-target="ios" href="${iosUrl}" target="_blank" rel="noopener noreferrer"><img src="/assets/images/ios.svg" alt="${esc(t.appStore)}"></a></div></section>
</main>
<footer class="site-footer"><div class="content-shell site-footer__inner"><span>© 2026 Chaput · ${esc(t.published)}</span><nav class="site-footer__links" aria-label="${lang === 'tr' ? 'Yasal bağlantılar' : 'Legal links'}"><a href="/legal/${lang}/privacy/">${esc(t.privacy)}</a><a href="/legal/${lang}/terms/">${esc(t.terms)}</a><a href="/legal/${lang}/community/">${esc(t.community)}</a><a href="/legal/">${esc(t.legal)}</a></nav></div></footer>
<script src="/assets/content.js" defer></script>
</body></html>`;
}

for (const page of pages) {
  for (const lang of ['en','tr']) {
    const path = resolve(root, lang === 'tr' ? 'tr' : '', page.slug, 'index.html');
    await mkdir(dirname(path), { recursive:true });
    await writeFile(path, render(page,lang));
  }
}

console.log(`Generated ${pages.length * 2} localized content pages.`);
